 10→ * Contains all of the code necessary to test a DNA scorer through multiple trials.
 11→ */
 12→public class ScoringRunner {
 13→
 14→    /**
 15→     * The constructor of a DNA scoring.
 16→     */
 17→    private final IScoringConstructor constructor;
 18→
 19→    /**
 20→     * Creates a runner.
 21→     *
 22→     * @param constructor provides the DNA scoring to run
 23→     */
 24→    public ScoringRunner(final IScoringConstructor constructor) {
 25→        this.constructor = constructor;
 26→    }
 27→
 28→    /**
 29→     * Starts the runner.
 30→     *
 31→     * @param mainName the name of the class that called this method
 32→     * @param args     the arguments that class was given, should be the names of two files
 33→     * @throws java.io.IOException on a file name or system problem
 34→     */
 35→    public void start(final String mainName, final String[] args) throws IOException {
 36→
 37→        // first read the two files as DNA sequences
 38→
 39→        final String filename1;
 40→        final String filename2;
 41→
 42→        if (args.length == 2) {
 43→            filename1 = args[0];
 44→            filename2 = args[1];
 45→            System.out.println("File Name-1: " + filename1);
 46→            System.out.println("File Name-2: " + filename2);
 47→        } else {
 48→            System.out.println("Usage: ./" + mainName + " fileName1 fileName2");
 49→            return;
 50→        }
 51→
 52→        final String X = initString(filename1);
 53→        final String Y = initString(filename2);
 54→        System.out.println("Size of input string 1 is " + X.length());
 55→        System.out.println("Size of input string 2 is " + Y.length());
 56→
 57→        // then test scorers created by the given constructor against the two sequences
 58→
 59→        final int xLength = X.length();
 60→        final int yLength = Y.length();
 61→        final int numIter = 5;
 62→        final long[] times = new long[numIter];
 63→        final int[] scores = new int[numIter];
 64→        long totalTime = 0;
 65→        long minTime = Long.MAX_VALUE;
 66→
 67→
 68→        for (int iter = 0; iter < numIter; iter++) {
 69→
 70→            final int iterLoc = iter;
 71→            final long[] execTime = {0};
 72→            launchHabaneroApp(() -> {
 73→                final AbstractDnaScoring scoring = constructor.create(xLength, yLength);
 74→                final long start = System.currentTimeMillis();
 75→
 76→                final int score = scoring.scoreSequences(X, Y);
 77→                scores[iterLoc] = score;
 78→
 79→                execTime[0] = System.currentTimeMillis() - start;
 80→                System.out.println("  The score = " + score + " in iteration " + (iterLoc + 1));
 81→                System.out.println("  The execution time = " + execTime[0] + " milliseconds in iteration " + (iterLoc + 1));
 82→            });
 83→            totalTime += execTime[0];
 84→            times[iter] = execTime[0];
 85→            if (execTime[0] < minTime) {
 86→                minTime = execTime[0];
 87→            }
 88→
 89→        }
 90→        for (int iter = 1; iter < numIter; iter++) {
 91→            if (scores[iter] != scores[0]) {
 92→                System.err.println("Different scores from different runs! " + scores[iter] + " and " + scores[0]);
 93→            }
 94→        }
 95→        System.out.println("Avg time of computation is " + totalTime / numIter);
 96→        System.out.println("Min time of computation is " + minTime + " milliseconds ");
 97→    }
 98→
 99→    /**
100→     * Read the sequence from a given text file.
101→     *
102→     * @param fileName The file name to read text from.
103→     * @return A string containing the sequence from the file.
104→     * @throws java.io.IOException if any.
105→     */
106→    private String initString(final String fileName) throws IOException {
107→        final BufferedReader r = new BufferedReader(new FileReader(fileName));
108→        final StringBuilder text = new StringBuilder();
109→        String line;
110→        while ((line = r.readLine()) != null) {
111→            text.append(line);
112→        }
113→        return text.toString();
114→    }
115→}
